class Solution:
    def solve(self, nums: List[int]) -> int:
        maxSub = nums[0]
        curSum = 0
        for n in nums:
            if curSum < 0: curSum = 0
            curSum += n
            maxSub = max(maxSub, curSum)
        return maxSub

